input.content:
package store

import (
	"context"
	"encoding/json"
	"fmt"
	"strconv"
	"strings"
	"sync"
	"time"

	"github.com/valkey-io/valkey-go"
	"k8s.io/klog/v2"
)

type ValkeyStore struct {
	client valkey.Client
	mu     sync.RWMutex
}

var _ Store = (*ValkeyStore)(nil)

func NewValkeyStore(addrs []string, password string, disableCache, forceSingle bool) (*ValkeyStore, error) {
	if len(addrs) == 0 {
		return nil, fmt.Errorf("valkey addresses cannot be empty")
	}

	clientOption := valkey.ClientOption{
		InitAddress: addrs,
		Password:    password,
		DisableCache: disableCache,
	}

	if forceSingle {
		clientOption.ForceSingleClient = true
	}

	client, err := valkey.NewClient(clientOption)
	if err != nil {
		return nil, fmt.Errorf("failed to create valkey client: %w", err)
	}

	store := &ValkeyStore{
		client: client,
	}

	return store, nil
}

func (v *ValkeyStore) Ping(ctx context.Context) error {
	result := v.client.B().Ping().Build()
	resp := v.client.Do(ctx, result)
	if resp.Error() != nil {
		return fmt.Errorf("valkey ping failed: %w", resp.Error())
	}

	msg, err := resp.ToString()
	if err != nil {
		return fmt.Errorf("failed to read ping response: %w", err)
	}

	if msg != "PONG" {
		return fmt.Errorf("unexpected valkey ping response: %s", msg)
	}

	return nil
}

func (v *ValkeyStore) GetSandboxBySessionID(ctx context.Context, sessionID string) (*SandboxInfo, error) {
	key := sessionKey(sessionID)

	result := v.client.B().Get().Key(key).Build()
	resp := v.client.Do(ctx, result)

	if resp.Error() != nil {
		if valkey.IsValkeyNil(resp.Error()) {
			return nil, ErrNotFound
		}
		return nil, fmt.Errorf("failed to get sandbox: %w", resp.Error())
	}

	data, err := resp.AsBytes()
	if err != nil {
		return nil, fmt.Errorf("failed to read response bytes: %w", err)
	}

	var sandbox SandboxInfo
	if err := json.Unmarshal(data, &sandbox); err != nil {
		return nil, fmt.Errorf("failed to unmarshal sandbox: %w", err)
	}

	return &sandbox, nil
}

func (v *ValkeyStore) StoreSandbox(ctx context.Context, sandbox *SandboxInfo) error {
	if sandbox == nil {
		return fmt.Errorf("sandbox cannot be nil")
	}
	if sandbox.ExpiresAt.IsZero() {
		return fmt.Errorf("sandbox expiresAt cannot be zero")
	}
	if sandbox.SessionID == "" {
		return fmt.Errorf("sandbox sessionId cannot be empty")
	}

	key := sessionKey(sandbox.SessionID)
	data, err := json.Marshal(sandbox)
	if err != nil {
		return fmt.Errorf("failed to marshal sandbox: %w", err)
	}

	now := time.Now()
	expiresAtScore := float64(sandbox.ExpiresAt.Unix())
	lastActivityScore := float64(now.Unix())

	pipe := v.client.B().Pipeline()

	setCmd := pipe.Set().Key(key).Value(string(data)).Nx(true).Build()

	pipe.Zadd().Key(SessionExpiryKey).MemberScore(
		valkey.Z{Score: expiresAtScore, Member: sandbox.SessionID},
	).Build()

	pipe.Zadd().Key(SessionLastActivity).MemberScore(
		valkey.Z{Score: lastActivityScore, Member: sandbox.SessionID},
	).Build()

	cmds, err := v.client.DoMulti(ctx, setCmd)
	if err != nil {
		return fmt.Errorf("pipeline failed: %w", err)
	}

	setResp := cmds[0]
	if setResp.Error() != nil {
		return fmt.Errorf("failed to execute SETNX: %w", setResp.Error())
	}

	val, err := setResp.AsInt64()
	if err != nil {
		return fmt.Errorf("failed to read SETNX response: %w", err)
	}

	if val == 0 {
		return fmt.Errorf("sandbox already exists for session %s", sandbox.SessionID)
	}

	return nil
}

func (v *ValkeyStore) UpdateSandbox(ctx context.Context, sandbox *SandboxInfo) error {
	if sandbox == nil {
		return fmt.Errorf("sandbox cannot be nil")
	}
	if sandbox.SessionID == "" {
		return fmt.Errorf("sandbox sessionId cannot be empty")
	}

	key := sessionKey(sandbox.SessionID)
	data, err := json.Marshal(sandbox)
	if err != nil {
		return fmt.Errorf("failed to marshal sandbox: %w", err)
	}

	result := v.client.B().Set().Key(key).Value(string(data)).Xx(true).Build()
	resp := v.client.Do(ctx, result)

	if resp.Error() != nil {
		return fmt.Errorf("failed to update sandbox: %w", resp.Error())
	}

	val, err := resp.AsInt64()
	if err != nil {
		return fmt.Errorf("failed to read SET response: %w", err)
	}

	if val == 0 {
		return fmt.Errorf("key not exists")
	}

	return nil
}

func (v *ValkeyStore) DeleteSandboxBySessionID(ctx context.Context, sessionID string) error {
	key := sessionKey(sessionID)

	pipe := v.client.B().Pipeline()

	pipe.Del().Key(key).Build()
	pipe.Zrem().Key(SessionExpiryKey).Member(sessionID).Build()
	pipe.Zrem().Key(SessionLastActivity).Member(sessionID).Build()

	cmds, err := v.client.DoMulti(ctx, pipe.Build())
	if err != nil {
		return fmt.Errorf("pipeline failed: %w", err)
	}

	delResp := cmds[0]
	delCount, err := delResp.AsInt64()
	if err != nil {
		return fmt.Errorf("failed to read DEL response: %w", err)
	}

	if delCount == 0 {
		return nil
	}

	return nil
}

func (v *ValkeyStore) ListExpiredSandboxes(ctx context.Context, before time.Time, limit int) ([]*SandboxInfo, error) {
	if limit <= 0 {
		return []*SandboxInfo{}, nil
	}

	maxScore := float64(before.Unix())

	result := v.client.B().Zrangebyscore().Key(SessionExpiryKey).Query(
		valkey.ZRangeByQuery{
			Min: "-inf",
			Max: strconv.FormatFloat(maxScore, 'f', -1, 64),
		},
	).Limit(int64(limit)).Build()

	resp := v.client.Do(ctx, result)
	if resp.Error() != nil {
		return nil, fmt.Errorf("failed to list expired sandboxes: %w", resp.Error())
	}

	sessionIDs, err := resp.AsStrSlice()
	if err != nil {
		return nil, fmt.Errorf("failed to read session IDs: %w", err)
	}

	return v.loadSandboxesBySessionIDs(ctx, sessionIDs)
}

func (v *ValkeyStore) ListInactiveSandboxes(ctx context.Context, before time.Time, limit int) ([]*SandboxInfo, error) {
	if limit <= 0 {
		return []*SandboxInfo{}, nil
	}

	maxScore := float64(before.Unix())

	result := v.client.B().Zrangebyscore().Key(SessionLastActivity).Query(
		valkey.ZRangeByQuery{
			Min: "-inf",
			Max: strconv.FormatFloat(maxScore, 'f', -1, 64),
		},
	).Limit(int64(limit)).Build()

	resp := v.client.Do(ctx, result)
	if resp.Error() != nil {
		return nil, fmt.Errorf("failed to list inactive sandboxes: %w", resp.Error())
	}

	sessionIDs, err := resp.AsStrSlice()
	if err != nil {
		return nil, fmt.Errorf("failed to read session IDs: %w", err)
	}

	return v.loadSandboxesBySessionIDs(ctx, sessionIDs)
}

func (v *ValkeyStore) UpdateSessionLastActivity(ctx context.Context, sessionID string, at time.Time) error {
	if sessionID == "" {
		return fmt.Errorf("sessionId cannot be empty")
	}

	key := sessionKey(sessionID)

	existsResult := v.client.B().Exists().Key(key).Build()
	existsResp := v.client.Do(ctx, existsResult)
	if existsResp.Error() != nil {
		return fmt.Errorf("failed to check session existence: %w", existsResp.Error())
	}

	exists, err := existsResp.AsInt64()
	if err != nil {
		return fmt.Errorf("failed to read EXISTS response: %w", err)
	}

	if exists == 0 {
		return ErrNotFound
	}

	if at.IsZero() {
		at = time.Now()
	}

	score := float64(at.Unix())

	addResult := v.client.B().Zadd().Key(SessionLastActivity).MemberScore(
		valkey.Z{Score: score, Member: sessionID},
	).Build()

	addResp := v.client.Do(ctx, addResult)
	if addResp.Error() != nil {
		return fmt.Errorf("failed to update last activity: %w", addResp.Error())
	}

	added, err := addResp.AsInt64()
	if err != nil {
		return fmt.Errorf("failed to read ZADD response: %w", err)
	}

	if added == 0 {
		klog.Warningf("session %s not found in last_activity index, re-adding", sessionID)
	}

	return nil
}

func (v *ValkeyStore) Close() error {
	v.client.Close()
	return nil
}

func (v *ValkeyStore) loadSandboxesBySessionIDs(ctx context.Context, sessionIDs []string) ([]*SandboxInfo, error) {
	if len(sessionIDs) == 0 {
		return []*SandboxInfo{}, nil
	}

	keys := make([]string, len(sessionIDs))
	for i, id := range sessionIDs {
		keys[i] = sessionKey(id)
	}

	var mgetArgs []string
	for _, k := range keys {
		mgetArgs = append(mgetArgs, k)
	}

	result := v.client.B().Mget().Key(mgetArgs...).Build()
	resp := v.client.Do(ctx, result)
	if resp.Error() != nil {
		return nil, fmt.Errorf("failed to load sandboxes: %w", resp.Error())
	}

	results, err := resp.AsStrSlice()
	if err != nil {
		return nil, fmt.Errorf("failed to read MGET response: %w", err)
	}

	sandboxes := make([]*SandboxInfo, 0, len(sessionIDs))
	for i, result := range results {
		if result == "" {
			continue
		}

		var sandbox SandboxInfo
		if err := json.Unmarshal([]byte(result), &sandbox); err != nil {
			klog.Warningf("failed to unmarshal sandbox %s: %v", sessionIDs[i], err)
			continue
		}

		sandboxes = append(sandboxes, &sandbox)
	}

	return sandboxes, nil
}

func splitValkeyAddresses(addr string) []string {
	if addr == "" {
		return nil
	}
	return strings.Split(addr, ",")
}

