func TestSandboxInfoJSONRoundTrip(t *testing.T) {
	original := &SandboxInfo{
		SandboxID: "sandbox-456",
		Name:      "roundtrip-test",
		SessionID: "session-xyz",
		Kind:      "CodeInterpreter",
		Namespace: "production",
		EntryPoints: []EntryPoint{
			{
				Path:     "/",
				Protocol: "HTTPS",
				Endpoint: "192.168.1.1:443",
				Name:     "main",
			},
			{
				Path:     "/health",
				Protocol: "HTTP",
				Endpoint: "192.168.1.1:8080",
			},
		},
		ExpiresAt: time.Date(2027, 1, 1, 0, 0, 0, 0, time.UTC),
		CreatedAt: time.Date(2026, 3, 26, 12, 0, 0, 0, time.UTC),
	}

	data, err := json.Marshal(original)
	if err != nil {
		t.Fatalf("failed to marshal: %v", err)
	}

	var decoded SandboxInfo
	err = json.Unmarshal(data, &decoded)
	if err != nil {
		t.Fatalf("failed to unmarshal: %v", err)
	}

	if decoded.SandboxID != original.SandboxID {
		t.Errorf("SandboxID mismatch: got %s, want %s", decoded.SandboxID, original.SandboxID)
	}
	if decoded.SessionID != original.SessionID {
		t.Errorf("SessionID mismatch: got %s, want %s", decoded.SessionID, original.SessionID)
	}
	if decoded.Kind != original.Kind {
		t.Errorf("Kind mismatch: got %s, want %s", decoded.Kind, original.Kind)
	}
	if len(decoded.EntryPoints) != len(original.EntryPoints) {
		t.Errorf("EntryPoints length mismatch: got %d, want %d", len(decoded.EntryPoints), len(original.EntryPoints))
	}
}

func TestEntryPointOptionalName(t *testing.T) {
