	if len(decoded.EntryPoints) != len(original.EntryPoints) {
		t.Errorf("EntryPoints length mismatch: got %d, want %d", len(decoded.EntryPoints), len(original.EntryPoints))
	}
}

func TestEntryPointOptionalName(t *testing.T) {
	ep := EntryPoint{
		Path:     "/api",
		Protocol: "HTTP",
		Endpoint: "localhost:8080",
	}

	if ep.Name != "" {
		t.Errorf("expected empty Name, got %s", ep.Name)
	}

	data, err := json.Marshal(ep)
	if err != nil {
		t.Fatalf("failed to marshal: %v", err)
	}

	var decoded EntryPoint
	err = json.Unmarshal(data, &decoded)
	if err != nil {
		t.Fatalf("failed to unmarshal: %v", err)
	}

	if decoded.Path != ep.Path {
		t.Errorf("Path mismatch: got %s, want %s", decoded.Path, ep.Path)
	}
}

func TestConfigRedisPasswordNotRequired(t *testing.T) {
	t.Setenv("STORE_TYPE", "redis")
	t.Setenv("REDIS_ADDR", "localhost:6379")
	t.Setenv("REDIS_PASSWORD", "")
	t.Setenv("REDIS_PASSWORD_REQUIRED", "false")

	config, err := LoadConfig()
	if err != nil {
		t.Fatalf("LoadConfig() error = %v", err)
	}

	if config.RedisPasswordRequired {
		t.Error("expected RedisPasswordRequired to be false")
	}
}

func TestConfigValkeyPasswordNotRequired(t *testing.T) {
	t.Setenv("STORE_TYPE", "valkey")
	t.Setenv("VALKEY_ADDR", "localhost:6379")
	t.Setenv("VALKEY_PASSWORD", "")
	t.Setenv("VALKEY_PASSWORD_REQUIRED", "false")

	config, err := LoadConfig()
	if err != nil {
		t.Fatalf("LoadConfig() error = %v", err)
	}

	if config.ValkeyPasswordRequired {
		t.Error("expected ValkeyPasswordRequired to be false")
	}
}

func TestConfigValkeyClientFlags(t *testing.T) {
	t.Setenv("STORE_TYPE", "valkey")
	t.Setenv("VALKEY_ADDR", "localhost:6379")
	t.Setenv("VALKEY_PASSWORD", "testpass")
	t.Setenv("VALKEY_DISABLE_CACHE", "true")
	t.Setenv("VALKEY_FORCE_SINGLE", "true")

	config, err := LoadConfig()
	if err != nil {
		t.Fatalf("LoadConfig() error = %v", err)
	}

	if !config.ValkeyDisableCache {
		t.Error("expected ValkeyDisableCache to be true")
	}

	if !config.ValkeyForceSingle {
		t.Error("expected ValkeyForceSingle to be true")
	}
}

func TestConfigValkeyAddrsParsing(t *testing.T) {
	t.Setenv("STORE_TYPE", "valkey")
	t.Setenv("VALKEY_ADDR", "host1:6379,host2:6379,host3:6379")
	t.Setenv("VALKEY_PASSWORD", "testpass")

	config, err := LoadConfig()
	if err != nil {
		t.Fatalf("LoadConfig() error = %v", err)
	}

	if len(config.ValkeyAddrs) != 3 {
		t.Errorf("expected 3 valkey addresses, got %d", len(config.ValkeyAddrs))
	}

	expectedAddrs := []string{"host1:6379", "host2:6379", "host3:6379"}
	for i, addr := range expectedAddrs {
		if config.ValkeyAddrs[i] != addr {
			t.Errorf("address %d mismatch: got %s, want %s", i, config.ValkeyAddrs[i], addr)
		}
	}
}

func TestSplitValkeyAddresses(t *testing.T) {
	tests := []struct {
		name     string
		input    string
		expected []string
	}{
		{
			name:     "single address",
			input:    "localhost:6379",
			expected: []string{"localhost:6379"},
		},
		{
			name:     "multiple addresses",
			input:    "host1:6379,host2:6379,host3:6379",
			expected: []string{"host1:6379", "host2:6379", "host3:6379"},
		},
		{
			name:     "empty string",
			input:    "",
			expected: nil,
		},
	}

	for _, tt := range tests {
		t.Run(tt.name, func(t *testing.T) {
			result := splitValkeyAddresses(tt.input)
			if len(result) != len(tt.expected) {
				t.Errorf("expected %d addresses, got %d", len(tt.expected), len(result))
				return
			}
			for i, addr := range result {
				if addr != tt.expected[i] {
					t.Errorf("address %d mismatch: got %s, want %s", i, addr, tt.expected[i])
				}
			}
		})
	}
}

