	"sigs.k8s.io/controller-runtime/pkg/client"
	"sigs.k8s.io/controller-runtime/pkg/controller/controllerutil"
)

const (
	LastActivityAnnotationKey = "last-activity-time"
	SessionExpirationTimeout  = 15 * time.Minute
)

type Reconciler struct {
	client.Client
}

func (r *Reconciler) Reconcile(ctx context.Context, req ctrl.Request) (ctrl.Result, error) {
	klog.V(4).InfoS("Reconciling Sandbox", "namespace", req.Namespace, "name", req.Name)

	sandbox := &sandboxv1alpha1.Sandbox{}
	if err := r.Get(ctx, req.NamespacedName, sandbox); err != nil {
		if errors.IsNotFound(err) {
			klog.V(4).InfoS("Sandbox not found, skipping", "namespace", req.Namespace, "name", req.Name)
			return ctrl.Result{}, nil
		}
		klog.ErrorS(err, "failed to get Sandbox", "namespace", req.Namespace, "name", req.Name)
		return ctrl.Result{}, err
	}

	lastActivityStr := sandbox.Annotations[LastActivityAnnotationKey]
	if lastActivityStr == "" {
		klog.V(4).InfoS("Sandbox missing last-activity annotation, skipping", 
			"namespace", req.Namespace, "name", req.Name)
		return ctrl.Result{}, nil
	}

	lastActivity, err := time.Parse(time.RFC3339, lastActivityStr)
	if err != nil {
		klog.ErrorS(err, "failed to parse last-activity-time annotation", 
			"namespace", req.Namespace, "name", req.Name, "value", lastActivityStr)
		return ctrl.Result{RequeueAfter: 30 * time.Second}, err
	}

	expirationTime := lastActivity.Add(SessionExpirationTimeout)
	now := time.Now()

	if now.After(expirationTime) {
		klog.InfoS("Sandbox idle timeout exceeded, deleting", 
			"namespace", req.Namespace, "name", req.Name,
			"lastActivity", lastActivity.Format(time.RFC3339),
			"expirationTime", expirationTime.Format(time.RFC3339))

		if err := r.Delete(ctx, sandbox); err != nil {
			if errors.IsNotFound(err) {
				klog.V(4).InfoS("Sandbox already deleted", "namespace", req.Namespace, "name", req.Name)
				return ctrl.Result{}, nil
			}
			klog.ErrorS(err, "failed to delete Sandbox", "namespace", req.Namespace, "name", req.Name)
			return ctrl.Result{}, err
		}

		klog.InfoS("Sandbox deleted successfully", "namespace", req.Namespace, "name", req.Name)
		return ctrl.Result{}, nil
	}

	requeueAfter := time.Until(expirationTime)
	if requeueAfter < 0 {
		requeueAfter = 0
	}

	klog.V(4).InfoS("Sandbox not yet expired, requeueing", 
		"namespace", req.Namespace, "name", req.Name,
		"requeueAfter", requeueAfter.String())

	return ctrl.Result{RequeueAfter: requeueAfter}, nil
}

func (r *Reconciler) SetupWithManager(mgr ctrl.Manager) error {
	return ctrl.NewControllerManagedBy(mgr).
		For(&sandboxv1alpha1.Sandbox{}).
		Complete(r)
}

func containsFinalizer(obj metav1.Object, finalizer string) bool {
	finalizers := obj.GetFinalizers()
	for _, f := range finalizers {
		if f == finalizer {
			return true
		}
	}
	return false
}

func addFinalizer(obj metav1.Object, finalizer string) {
	finalizers := obj.GetFinalizers()
	if !containsFinalizer(obj, finalizer) {
		finalizers = append(finalizers, finalizer)
		obj.SetFinalizers(finalizers)
	}
}

func removeFinalizer(obj metav1.Object, finalizer string) {
	finalizers := obj.GetFinalizers()
	newFinalizers := make([]string, 0, len(finalizers))
	for _, f := range finalizers {
		if f != finalizer {
			newFinalizers = append(newFinalizers, f)
		}
	}
	obj.SetFinalizers(newFinalizers)
}

