package agentd

import (
	"context"
	"testing"
	"time"

	metav1 "k8s.io/apimachinery/pkg/apis/meta/v1"
	"k8s.io/apimachinery/pkg/apis/meta/v1/unstructured"
	"k8s.io/apimachinery/pkg/runtime"
	"k8s.io/apimachinery/pkg/runtime/schema"
	"sigs.k8s.io/controller-runtime/pkg/client"
	"sigs.k8s.io/controller-runtime/pkg/client/fake"
)

func TestReconcilerMissingSandbox(t *testing.T) {
	scheme := runtime.NewScheme()
	fakeClient := fake.NewClientBuilder().WithScheme(scheme).Build()

	reconciler := &Reconciler{
		Client: fakeClient,
	}

	ctx := context.Background()
	req := metav1.ObjectMeta{
		Namespace: "default",
		Name:      "nonexistent",
	}

	result, err := reconciler.Reconcile(ctx, client.ObjectKey{
		Namespace: req.Namespace,
		Name:      req.Name,
	})

	if err != nil {
		t.Fatalf("expected no error, got %v", err)
	}

	if result.Requeue {
		t.Error("expected no requeue, got true")
	}

	if result.RequeueAfter != 0 {
		t.Errorf("expected RequeueAfter 0, got %v", result.RequeueAfter)
	}
}

func TestReconcilerMissingAnnotation(t *testing.T) {
	scheme := runtime.NewScheme()

	sandbox := &unstructured.Unstructured{}
	sandbox.SetGroupVersionKind(schema.GroupVersionKind{
		Group:   "agents.x-k8s.io",
		Version: "v1alpha1",
		Kind:    "Sandbox",
	})
	sandbox.SetNamespace("default")
	sandbox.SetName("test-sandbox")
	sandbox.SetAnnotations(map[string]string{})

	fakeClient := fake.NewClientBuilder().
		WithScheme(scheme).
		WithObjects(sandbox).
		Build()

	reconciler := &Reconciler{
		Client: fakeClient,
	}

	ctx := context.Background()

	result, err := reconciler.Reconcile(ctx, client.ObjectKey{
		Namespace: "default",
		Name:      "test-sandbox",
	})

	if err != nil {
		t.Fatalf("expected no error, got %v", err)
	}

	if result.Requeue {
		t.Error("expected no requeue, got true")
	}

	if result.RequeueAfter != 0 {
		t.Errorf("expected RequeueAfter 0, got %v", result.RequeueAfter)
	}
}

func TestReconcilerInvalidTimestamp(t *testing.T) {
	scheme := runtime.NewScheme()

	sandbox := &unstructured.Unstructured{}
	sandbox.SetGroupVersionKind(schema.GroupVersionKind{
		Group:   "agents.x-k8s.io",
		Version: "v1alpha1",
		Kind:    "Sandbox",
	})
	sandbox.SetNamespace("default")
	sandbox.SetName("test-sandbox")
	sandbox.SetAnnotations(map[string]string{
		LastActivityAnnotationKey: "invalid-timestamp",
	})

	fakeClient := fake.NewClientBuilder().
		WithScheme(scheme).
		WithObjects(sandbox).
		Build()

	reconciler := &Reconciler{
		Client: fakeClient,
	}

	ctx := context.Background()

	result, err := reconciler.Reconcile(ctx, client.ObjectKey{
		Namespace: "default",
		Name:      "test-sandbox",
	})

	if err == nil {
		t.Fatal("expected error for invalid timestamp, got nil")
	}

	if result.RequeueAfter != 30*time.Second {
		t.Errorf("expected RequeueAfter 30s, got %v", result.RequeueAfter)
	}
}

func TestReconcilerNotYetExpired(t *testing.T) {
	scheme := runtime.NewScheme()

	sandbox := &unstructured.Unstructured{}
	sandbox.SetGroupVersionKind(schema.GroupVersionKind{
		Group:   "agents.x-k8s.io",
		Version: "v1alpha1",
		Kind:    "Sandbox",
	})
	sandbox.SetNamespace("default")
	sandbox.SetName("test-sandbox")

	now := time.Now()
	sandbox.SetAnnotations(map[string]string{
		LastActivityAnnotationKey: now.Format(time.RFC3339),
	})

	fakeClient := fake.NewClientBuilder().
		WithScheme(scheme).
		WithObjects(sandbox).
		Build()

	reconciler := &Reconciler{
		Client: fakeClient,
	}

	ctx := context.Background()

	result, err := reconciler.Reconcile(ctx, client.ObjectKey{
		Namespace: "default",
		Name:      "test-sandbox",
	})

	if err != nil {
		t.Fatalf("expected no error, got %v", err)
	}

	if result.RequeueAfter <= 0 {
		t.Error("expected positive RequeueAfter, got 0 or negative")
	}

	if result.RequeueAfter > SessionExpirationTimeout {
		t.Errorf("expected RequeueAfter <= %v, got %v", SessionExpirationTimeout, result.RequeueAfter)
	}
}

func TestReconcilerExpired(t *testing.T) {
	scheme := runtime.NewScheme()

	sandbox := &unstructured.Unstructured{}
	sandbox.SetGroupVersionKind(schema.GroupVersionKind{
		Group:   "agents.x-k8s.io",
		Version: "v1alpha1",
		Kind:    "Sandbox",
	})
	sandbox.SetNamespace("default")
	sandbox.SetName("test-sandbox")

	expiredTime := time.Now().Add(-20 * time.Minute)
	sandbox.SetAnnotations(map[string]string{
		LastActivityAnnotationKey: expiredTime.Format(time.RFC3339),
	})

	fakeClient := fake.NewClientBuilder().
		WithScheme(scheme).
		WithObjects(sandbox).
		Build()

	reconciler := &Reconciler{
		Client: fakeClient,
	}

	ctx := context.Background()

	result, err := reconciler.Reconcile(ctx, client.ObjectKey{
		Namespace: "default",
		Name:      "test-sandbox",
	})

	if err != nil {
		t.Fatalf("expected no error, got %v", err)
	}

	_ = result
}

func TestReconcilerConstants(t *testing.T) {
	if LastActivityAnnotationKey != "last-activity-time" {
		t.Errorf("expected LastActivityAnnotationKey to be 'last-activity-time', got %s", LastActivityAnnotationKey)
	}

	if SessionExpirationTimeout != 15*time.Minute {
		t.Errorf("expected SessionExpirationTimeout to be 15m, got %v", SessionExpirationTimeout)
	}
}

func TestReconcilerEdgeCases(t *testing.T) {
	t.Run("nil annotations", func(t *testing.T) {
		scheme := runtime.NewScheme()

		sandbox := &unstructured.Unstructured{}
		sandbox.SetGroupVersionKind(schema.GroupVersionKind{
			Group:   "agents.x-k8s.io",
			Version: "v1alpha1",
			Kind:    "Sandbox",
		})
		sandbox.SetNamespace("default")
		sandbox.SetName("test-sandbox")
		sandbox.SetAnnotations(nil)

		fakeClient := fake.NewClientBuilder().
			WithScheme(scheme).
			WithObjects(sandbox).
			Build()

		reconciler := &Reconciler{
			Client: fakeClient,
		}

		ctx := context.Background()

		result, err := reconciler.Reconcile(ctx, client.ObjectKey{
			Namespace: "default",
			Name:      "test-sandbox",
		})

		if err != nil {
			t.Fatalf("expected no error, got %v", err)
		}

		if result.Requeue {
			t.Error("expected no requeue")
		}
	})

	t.Run("exactly at expiration boundary", func(t *testing.T) {
		scheme := runtime.NewScheme()

		sandbox := &unstructured.Unstructured{}
		sandbox.SetGroupVersionKind(schema.GroupVersionKind{
			Group:   "agents.x-k8s.io",
			Version: "v1alpha1",
			Kind:    "Sandbox",
		})
		sandbox.SetNamespace("default")
		sandbox.SetName("test-sandbox")

		expirationTime := time.Now().Add(-SessionExpirationTimeout)
		sandbox.SetAnnotations(map[string]string{
			LastActivityAnnotationKey: expirationTime.Format(time.RFC3339),
		})

		fakeClient := fake.NewClientBuilder().
			WithScheme(scheme).
			WithObjects(sandbox).
			Build()

		reconciler := &Reconciler{
			Client: fakeClient,
		}

		ctx := context.Background()

		result, err := reconciler.Reconcile(ctx, client.ObjectKey{
			Namespace: "default",
			Name:      "test-sandbox",
		})

		if err != nil {
			t.Fatalf("expected no error, got %v", err)
		}

		_ = result
